mapper.update:
UPDATE Cards
SET current_usage = #{usage}
WHERE card_id = #{cardId}

UPDATE Cards
SET current_usage = current_usage + #{amount}
WHERE card_id = #{cardId}
  AND card_status = 'ACTIVE'
  AND is_deleted = 0
  AND current_usage + #{amount} <= monthly_limit

UPDATE Cards
SET current_usage = CASE WHEN current_usage - #{amount} < 0 THEN 0 ELSE current_usage - #{amount} END
WHERE card_id = #{cardId}
